namespace sv_89f0f05f67fa4ec891a52744ad842c48.Services;

/// <summary>
/// Scoped service holding the currently selected warehouse for a single circuit (user session).
/// Fires <see cref="OnChange"/> so any subscribed component can re-render when the selection changes.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_89f0f05f67fa4ec891a52744ad842c48.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and broadcasts results to all subscribers
/// within the same circuit. Polling is ref-counted: starts on first subscriber, stops when
/// the last subscriber leaves.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private readonly Lock _lock = new();

    private CancellationTokenSource? _pollCts;
    private int _subscriberCount;
    private int _lastAlertCount;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    public int LastAlertCount => _lastAlertCount;

    /// <summary>
    /// Raised on the polling thread whenever new alert data is available.
    /// Subscribers must marshal to the UI thread via InvokeAsync.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>Simulates a database query returning 0-15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>Increment subscriber count; start polling if this is the first.</summary>
    public void Subscribe()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1)
                StartPolling();
        }
    }

    /// <summary>Decrement subscriber count; stop polling if this was the last.</summary>
    public void Unsubscribe()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount == 0)
                StopPolling();
        }
    }

    /// <summary>Force an immediate poll (e.g. after warehouse change).</summary>
    public async Task RefreshAsync()
    {
        await PollOnceAsync();
    }

    private void StartPolling()
    {
        StopPolling();
        _pollCts = new CancellationTokenSource();
        _ = PollLoopAsync(_pollCts.Token);
    }

    private void StopPolling()
    {
        _pollCts?.Cancel();
        _pollCts?.Dispose();
        _pollCts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await PollOnceAsync();

            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task PollOnceAsync()
    {
        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        _lastAlertCount = count;

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    public void Dispose()
    {
        StopPolling();
    }
}

