<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            @if (_alertCount > 0)
            {
                <span class="badge bg-danger fs-6">@_alertCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-6">None</span>
