<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            @if (_alertCount > 0)
            {
                <span class="badge bg-danger fs-6">@_alertCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-6">None</span>
            }
        </p>
        <p class="text-muted small mb-0">Polling every 10 seconds. Last update: @_lastUpdate.ToString("T")</p>
    </div>
</div>

@code {
    private int _alertCount;
    private DateTime _lastUpdate = DateTime.Now;

    protected override void OnInitialized()
    {
        _alertCount = AlertService.LastAlertCount;
        AlertService.OnAlertCountChanged += OnAlertDataChanged;
        AlertService.Subscribe();

        WarehouseState.OnChange += OnWarehouseChanged;
    }

    private async Task OnAlertDataChanged()
    {
        _alertCount = AlertService.LastAlertCount;
        _lastUpdate = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private void OnWarehouseChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnAlertDataChanged;
        AlertService.Unsubscribe();
        WarehouseState.OnChange -= OnWarehouseChanged;
    }
}

